parameters.jsCode:
const aiRaw = $input.first().json;
const trigger = $('Trigger').first().json;
const recordId = trigger.contentId || trigger.id || '';
const handleIg = trigger.brand?.handle_ig || 'marca';

let title = '';
let body_text = '';
let image_prompt = '';

try {
  const content = aiRaw.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(content);
  title = parsed.title || '';
  body_text = parsed.body_text || '';
  image_prompt = parsed.image_prompt || '';
} catch (e) {
  title = 'Error al parsear';
  image_prompt = '';
}

return [{
  json: {
    recordId,
    tenantId: trigger.tenantId || null,
    title,
    body_text,
    footer: `@${handleIg}`,
    image_prompt
  }
}];

// Extraer id de la escena creada (Supabase devuelve array)
const raw = $input.first().json;
const scene = Array.isArray(raw) ? raw[0] : raw;
const postData = $('2. Parsear estructura').first().json;
return [{ json: { ...postData, sceneId: scene.id } }];

const callback = $input.first().json;
const sceneData = $('Extraer ID escena').first().json;
const escenaId = sceneData.sceneId;

let imageUrl = '';
let estado = 'Listo';
let errorMsg = '';

const apiMsg = callback.msg || callback.body?.msg || '';
const apiCode = callback.body?.code || callback.code;

let imageRetryCount = 0;
try {
  const prev = $('6. Procesar resultado').first().json;
  if (prev.retryable) { imageRetryCount = prev.imageRetryCount || 0; }
} catch (e) {}

const retryableCodes = [500, 501, 502, 503];
const retryableMessages = ['internal error', 'try again', 'server busy', 'temporarily unavailable'];
const isRetryable = (apiCode && retryableCodes.includes(apiCode)) || retryableMessages.some(m => apiMsg.toLowerCase().includes(m));

if (isRetryable && imageRetryCount < 3) {
  return [{ json: { escenaId, imageUrl: '', estado: 'Reintentando', errorMsg: 'Retry ' + (imageRetryCount + 1) + '/3: code=' + (apiCode || '') + ' ' + apiMsg, retryable: true, imageRetryCount: imageRetryCount + 1, recordId: sceneData.recordId, tenantId: sceneData.tenantId } }];
}

if (apiMsg && (apiMsg.toLowerCase().includes('credit') || apiMsg.toLowerCase().includes('fail'))) {
  return [{ json: { escenaId, imageUrl: '', estado: 'Error', errorMsg: apiMsg, retryable: false, recordId: sceneData.recordId, tenantId: sceneData.tenantId } }];
}

try {
  const resultJson = JSON.parse(callback.body.data.resultJson);
  imageUrl = resultJson.resultUrls?.[0] || '';
} catch (e) {
  estado = 'Error';
  errorMsg = 'Failed to parse: ' + e.message;
}

if (!imageUrl && estado !== 'Error') {
  estado = 'Error';
  errorMsg = 'No image URL';
}

return [{ json: { escenaId, imageUrl, estado, errorMsg, retryable: false, recordId: sceneData.recordId, tenantId: sceneData.tenantId } }];

// Configuración hardcoded del modelo Kie.ai (no hay tabla en Supabase todavía)
const endpoint = 'https://api.kie.ai/api/v1/jobs/createTask';
const bodyTemplate = JSON.stringify({
  type: 'img2img',
  model: 'nano-banana-pro',
  prompt: '{prompt}',
  aspect_ratio: '{aspect_ratio}',
  callback_url: '{callback_url}'
});
return [{ json: { endpoint, bodyTemplate } }];

const modelo = $('Fetch modelo imagen').first().json;
const bodyTemplate = modelo['bodyTemplate'] || '';
const endpoint = modelo.endpoint || 'https://api.kie.ai/api/v1/jobs/createTask';
const prompt = $('Extraer ID escena').first().json.image_prompt || '';
const aspectRatio = '1:1';

const escapedPrompt = JSON.stringify(prompt).slice(1, -1);
const body = bodyTemplate
  .replace(/\{prompt\}/g, escapedPrompt)
  .replace(/\{aspect_ratio\}/g, aspectRatio);

return [{ json: { endpoint, bodyWithCallback: body } }];

const original = $('6. Procesar resultado').first().json;
const wm = $input.first().json;
const imageUrl = (wm.success && wm.url) ? wm.url : (original.imageUrl || '');
return [{ json: {
  escenaId: original.escenaId,
  imageUrl,
  estado: original.estado,
  errorMsg: original.errorMsg || '',
  recordId: original.recordId,
  tenantId: original.tenantId
} }];

const brand = $('Trigger').first().json.brand || {};
const style = $('Trigger').first().json.style_prompts || {};
const trigger = $('Trigger').first().json;

let systemPrompt = style.prompt_sistema || '';
systemPrompt = systemPrompt
  .replace(/{brand_name}/g, brand.nombre || '')
  .replace(/{handle_ig}/g, brand.handle_ig || '')
  .replace(/{tono}/g, brand.tono || '')
  .replace(/{audiencia}/g, brand.audiencia || '')
  .replace(/{colores}/g, brand.colores || '')
  .replace(/{estilo_visual}/g, brand.estilo_visual || '')
  .replace(/{reglas_lenguaje}/g, brand.reglas_lenguaje || '');

if (!systemPrompt) {
  systemPrompt = `Eres un Art Director de ${brand.nombre || 'la marca'}. Genera posts estaticos de Instagram. Colores: ${brand.colores}. IDIOMA: textos en ESPANOL, image_prompt en ingles. SIEMPRE responde en JSON valido.`;
}

let userPrompt = style.prompt_usuario || '';
userPrompt = userPrompt
  .replace(/{mi_hook}/g, trigger.mi_hook || '')
  .replace(/{mi_caption}/g, trigger.mi_caption || '')
  .replace(/{analisis}/g, trigger.analisis || '')
  .replace(/{brand_name}/g, brand.nombre || '')
  .replace(/{handle_ig}/g, brand.handle_ig || '')
  .replace(/{colores}/g, brand.colores || '');

if (!userPrompt) {
  userPrompt = `Genera 1 post estatico de Instagram.\nHOOK: ${trigger.mi_hook || ''}\nCAPTION: ${trigger.mi_caption || ''}\nCONTEXTO: ${trigger.analisis || ''}\n\nJSON con title, body_text, footer (@${brand.handle_ig || 'marca'}), image_prompt.`;
}

return [{ json: { ...trigger, systemPrompt, userPrompt } }];
